mapper.select:
SELECT order_num, work_order_id, plan_id, item_name, order_qty, ename, order_start, work_status, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT wo.order_num, wo.order_id AS work_order_id, pp.plan_id, i.name AS item_name, wo.order_qty, e.ename, wo.order_start, wo.order_status AS work_status, f.facility_name, COUNT(*) OVER() AS total_count FROM work_order wo LEFT JOIN emp e ON wo.emp_num = e.emp_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN item i ON pp.item_num = i.item_num LEFT JOIN ( SELECT item_num, facility_num FROM ( SELECT item_num, facility_num, ROW_NUMBER() OVER (PARTITION BY item_num ORDER BY flow) AS rn FROM process WHERE facility_num IS NOT NULL ) WHERE rn = 1 ) pr ON i.item_num = pr.item_num LEFT JOIN facility f ON pr.facility_num = f.facility_num
AND wo.order_start >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND wo.order_start <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND wo.order_status = #{work_status}
AND (wo.order_id LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY wo.order_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.update:
UPDATE work_order
SET order_status = #{work_status}
WHERE order_id = #{work_order_id}
